import React from 'react';
import moment from 'moment';
import { history } from 'umi';
import AnalysisStore, { enum_date_type } from '@/store/Analysis/typings';
import { DATE_TYPE_LIST, QUICK_DATE_TYPE_LIST, enum_quick_date_type } from '../constant';
import { formatDate } from '@/utils/method';
import { Radio, DatePicker, Popover, ConfigProvider } from 'antd';
import zhCN from 'antd/es/locale/zh_CN';
import styles from './DateSelector.less';

const { RangePicker } = DatePicker;

interface IProps {
    ifShow: boolean; // 控制日期区间选择弹窗的显示隐藏
    toggleDateModal: (event?: React.MouseEvent<HTMLDivElement, MouseEvent>) => void; // 日期区间选择弹窗的显示隐藏事件
    dateTypeChangeHandler: (value: enum_date_type) => void; // 日K 周K 月K 切换时调用的方法
    dateRangeChangeHandler: Function; // 选项变化后的处理事件
    analysisStore: AnalysisStore;
}

interface IState {
    selectedStartDate: string; // 当前选中的开始日期
    selectedEndDate: string; // 当前选中的结束日期
}

class DateSelector extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            selectedStartDate: '',
            selectedEndDate: ''
        };
    }
    /**
     * 日期选择框被点击，阻止事件冒泡，由于在最外层增加了点击空白处关闭日期弹窗
     * @param event 事件对象
     * @return {void}
     */
    datePopoverClick = event => {
        event.stopPropagation();
    };
    /**
     * 日期选择的快捷选择
     * @param value 选中的快捷选择方式
     * @return {void}
     */
    quickSelect = value => () => {
        const { analysisStore, toggleDateModal, dateRangeChangeHandler } = this.props;
        const { changeSelectedDateRange, changeDateType, changeChartHeaderTips } = analysisStore;
        const endTime = new Date(); // 结束时间 就是今天
        const endStr = formatDate(new Date(), 'YYYY-MM-DD');
        let startStr = '', // 开始时间
            dateType = enum_date_type.day;
        switch (value) {
            case enum_quick_date_type.today:
                history.push('/');
                return;
            case enum_quick_date_type.thisWeek:
                const weekNo = endTime.getDay(); // 今天周几
                const mondayTime = new Date(endTime.getTime() - (weekNo - 1) * 24 * 60 * 60 * 1000); // 本周周一的日期    weekNo - 1 = 距离周一已经过了几天
                startStr = formatDate(mondayTime, 'YYYY-MM-DD');
                changeChartHeaderTips(`${startStr} ~ ${formatDate(endTime, 'YYYY-MM-DD')}`);
                break;
            case enum_quick_date_type.thisMonth:
                changeChartHeaderTips(formatDate(endTime, 'YYYY-MM'));
                startStr = formatDate(endTime, 'YYYY-MM-01');
                break;
            case enum_quick_date_type.thisYear:
                changeChartHeaderTips(formatDate(endTime, 'YYYY'));
                startStr = formatDate(endTime, 'YYYY-01-01');
                dateType = enum_date_type.month;
                break;
        }
        toggleDateModal();
        changeDateType(dateType);
        changeSelectedDateRange({
            startDate: startStr,
            endDate: endStr
        });
        dateRangeChangeHandler();
    };
    /**
     * 日期选择器变化
     * @param {Moment[]} value 选中的日期 moment value[0]是开始时间  value[1]是结束时间
     * @return {void}
     */
    changeDate = value => {
        if (value) {
            const [startDate, endDate] = value;
            const getDateStr = date => moment(date).format('YYYY-MM-DD');
            this.setState({ selectedStartDate: getDateStr(startDate), selectedEndDate: getDateStr(endDate) });
        } else {
            this.setState({ selectedStartDate: '', selectedEndDate: '' });
        }
    };
    // 确定按钮点击 确认选择的时间区间
    confirmDate = () => {
        const { selectedStartDate, selectedEndDate } = this.state;
        const { analysisStore, toggleDateModal, dateRangeChangeHandler } = this.props;
        const { changeSelectedDateRange, changeDateType, changeChartHeaderTips } = analysisStore;
        if (!selectedEndDate || !selectedStartDate) return;
        toggleDateModal();
        changeChartHeaderTips('');
        changeSelectedDateRange({
            startDate: selectedStartDate,
            endDate: selectedEndDate
        });
        changeDateType(enum_date_type.day);
        dateRangeChangeHandler({
            startDate: selectedStartDate,
            endDate: selectedEndDate
        });
    };

    render() {
        const _this = this;
        const { ifShow, analysisStore, toggleDateModal, dateTypeChangeHandler } = _this.props;
        const { selectedDateType, selectedDateRange } = analysisStore;
        const dateSelectPopover = (
            <div className={styles.dateSelectPopover} onClick={_this.datePopoverClick}>
                <div className={styles.dateSelectorCard}>
                    <div className="dateSelector">
                        <ConfigProvider locale={zhCN}>
                            <RangePicker onChange={_this.changeDate} format="YYYY/MM/DD" />
                        </ConfigProvider>
                    </div>
                    <div onClick={_this.confirmDate} className={styles.confirmBtn}>
                        确定
                    </div>
                </div>
                <div className={styles.quickSelector}>
                    <div className={styles.quickSelectorTitle}>快捷选择</div>
                    <div className={styles.quickSelectorContainer}>
                        {QUICK_DATE_TYPE_LIST.map(item => (
                            <div key={item.value} className={styles.quickBtn} onClick={_this.quickSelect(item.value)}>
                                {item.title}
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        );
        return (
            <div id="page-analysis-dateSelector" className={styles.dateSelector}>
                <Radio.Group defaultValue={-1} value={selectedDateType} buttonStyle="solid">
                    {DATE_TYPE_LIST.map(item => (
                        <Radio.Button
                            key={item.value}
                            value={item.value}
                            onClick={() => dateTypeChangeHandler(item.value)}
                            className={selectedDateRange.endDate ? 'clearSelected' : ''}
                        >
                            {item.title}
                        </Radio.Button>
                    ))}
                </Radio.Group>
                <Popover
                    defaultVisible={false}
                    arrowPointAtCenter
                    placement="bottomRight"
                    visible={ifShow}
                    content={dateSelectPopover}
                    trigger="click"
                >
                    <div
                        onClick={toggleDateModal}
                        className={`${styles.selectDateBtn} ${selectedDateRange.endDate ? styles.selectedDateBtn : ''}`}
                    >
                        {selectedDateRange.endDate ? (
                            <React.Fragment>
                                <div className={styles.selectDateBtnText}>{selectedDateRange.startDate}</div>
                                <div className={styles.selectDateBtnText}>{selectedDateRange.endDate}</div>
                            </React.Fragment>
                        ) : (
                            '选择日期'
                        )}
                    </div>
                </Popover>
            </div>
        );
    }
}

export default DateSelector;
