import React from 'react';
import AnalysisStore, {
    enum_chart_type,
    enum_xAxis_type,
    enum_date_type,
    enum_order_discount_type
} from '@/store/Analysis/typings';
import { formatDate, downloadFile } from '@/utils/method';
import { enum_wash_type, enum_file_type } from '@/utils/constant';
import { Radio } from 'antd';
import styles from './ChartHeader.less';

interface IProps {
    mainChartData: Record<string, any>[]; // 主要chart图表的渲染数据
    headerData: Record<string, any>[]; // 图表上方legend的数据
    xAxisTypeChangeHandler: (e) => void; // 时间 和 地区切换时调用
    analysisStore: AnalysisStore;
}

class ChartHeader extends React.Component<IProps> {
    constructor(props: IProps) {
        super(props);
    }

    exportData = async () => {
        const {
            selectedDateRange,
            selectedDateType,
            selectedChartType,
            selectedXAxisType,
            exportOrderCountAnalysis,
            exportRevenueAnalysis,
            exportPositiveRateAnalysis,
            exportShareRateAnalysis,
            exportRepurchaseRateAnalysis
        } = this.props.analysisStore;
        const otherParams = { type: selectedDateType };
        if (selectedXAxisType !== enum_xAxis_type.time) {
            otherParams.type = 0;
            otherParams['group_province'] = 1;
        }
        const { startDate, endDate } = selectedDateRange;
        let result,
            fileName = '';
        if (startDate || endDate) {
            const params = {
                startTime: startDate,
                endTime: endDate,
                ...otherParams
            };
            // 已经有开始时间和结束时间，则直接使用
            switch (selectedChartType) {
                case enum_chart_type.orderCount:
                    result = await exportOrderCountAnalysis(params);
                    fileName = `${startDate}至${endDate}单量数据`;
                    break;
                case enum_chart_type.revenue:
                    result = await exportRevenueAnalysis(params);
                    fileName = `${startDate}至${endDate}营收数据`;
                    break;
                case enum_chart_type.positiveRate:
                    result = await exportPositiveRateAnalysis(params);
                    fileName = `${startDate}至${endDate}好评率数据`;
                    break;
                case enum_chart_type.shareRate:
                    result = await exportShareRateAnalysis(params);
                    fileName = `${startDate}至${endDate}分享率数据`;
                    break;
                case enum_chart_type.repurchaseRate:
                    result = await exportRepurchaseRateAnalysis(params);
                    fileName = `${startDate}至${endDate}复购率数据`;
                    break;
            }
            const { data } = result;
            data && downloadFile({ file: data, name: fileName, type: enum_file_type.excel });
            return;
        }
        const endTime = new Date(); // 结束时间 就是今天
        const endStr = formatDate(new Date(), 'YYYY-MM-DD');
        let startTime = endTime,
            startStr = ''; // 开始时间
        switch (selectedDateType) {
            case enum_date_type.day:
                startTime = new Date(endTime.getTime() - 30 * 24 * 60 * 60 * 1000); // 计算30天前的日期
                startStr = formatDate(startTime, 'YYYY-MM-DD');
                break;
            case enum_date_type.week:
                const weekNo = endTime.getDay(); // 今天周几
                const mondayTime = endTime.getTime() - (weekNo > 1 ? weekNo - 1 : weekNo) * 24 * 60 * 60 * 1000; // 本周周一的日期    weekNo - 1 = 距离周一已经过了几天
                startTime = new Date(mondayTime - 25 * 7 * 24 * 60 * 60 * 1000); // 25 * 7 计算25周前的周一日期，
                startStr = formatDate(startTime, 'YYYY-MM-DD');
                break;
            case enum_date_type.month:
                startStr = endTime.getFullYear() - 1 + '-01-01'; // 前一年的1月1日
                break;
        }
        const params = {
            startTime: startStr,
            endTime: endStr,
            ...otherParams
        };
        switch (selectedChartType) {
            case enum_chart_type.orderCount:
                result = await exportOrderCountAnalysis(params);
                fileName = `${startStr}至${endStr}单量数据`;
                break;
            case enum_chart_type.revenue:
                result = await exportRevenueAnalysis(params);
                fileName = `${startStr}至${endStr}营收数据`;
                break;
            case enum_chart_type.positiveRate:
                result = await exportPositiveRateAnalysis(params);
                fileName = `${startStr}至${endStr}好评率数据`;
                break;
            case enum_chart_type.shareRate:
                result = await exportShareRateAnalysis(params);
                fileName = `${startStr}至${endStr}分享率数据`;
                break;
            case enum_chart_type.repurchaseRate:
                result = await exportRepurchaseRateAnalysis(params);
                fileName = `${startStr}至${endStr}复购率数据`;
                break;
        }
        const { data } = result;
        data && downloadFile({ file: data, name: fileName, type: enum_file_type.excel });
    };

    render() {
        const _this = this;
        const { mainChartData, headerData, xAxisTypeChangeHandler, analysisStore } = this.props;
        const { selectedChartType, selectedXAxisType, chartHeaderTips } = analysisStore;
        // 计算 原价洗和优惠洗的好评率 平均值，返回{平均值 原价洗 优惠洗}
        const getPositiveRateAve = (): {
            all: string;
            [enum_order_discount_type.origin]: string;
            [enum_order_discount_type.discount]: string;
        } => {
            const positiveObj = {
                all: '0.00%',
                [enum_order_discount_type.origin]: '0.00%',
                [enum_order_discount_type.discount]: '0.00%'
            };
            if (headerData.length > 0) {
                headerData.forEach(item => {
                    positiveObj[item.f_type] = item.f_washOrderTypeRate.toFixed(2) + '%';
                });
                positiveObj['all'] =
                    (
                        Object.values(positiveObj).reduce((preTotal, item) => preTotal + +item.split('%')[0], 0) / 2
                    ).toFixed(2) + '%';
            }
            return positiveObj;
        };

        return (
            <div className={styles.mainHeader}>
                <div className={styles.mainHeaderLeft}>
                    {/* 左上角的legend */}
                    {/* 单量 分享率 复购率 legend */}
                    {(selectedChartType === enum_chart_type.orderCount ||
                        selectedChartType === enum_chart_type.shareRate ||
                        selectedChartType === enum_chart_type.repurchaseRate) && (
                        <React.Fragment>
                            <div>
                                {selectedChartType === enum_chart_type.orderCount &&
                                    ((mainChartData.length > 0 &&
                                        mainChartData
                                            .reduce((preTotal, item) => preTotal + item.num || 0, 0)
                                            .toFixed(0)) ||
                                        0)}
                                {(selectedChartType === enum_chart_type.shareRate ||
                                    selectedChartType === enum_chart_type.repurchaseRate) &&
                                    ((mainChartData.length > 0 &&
                                        (
                                            mainChartData.reduce(
                                                (preTotal, item) => preTotal + item.share_rate || 0,
                                                0
                                            ) / mainChartData.length
                                        ).toFixed(2)) ||
                                        '0.00')}
                            </div>
                            <div className={styles.mainHeaderLeftTip}>
                                <div className={styles.dateTip}>{chartHeaderTips}</div>
                                <div className={styles.unit}>
                                    {selectedChartType === enum_chart_type.orderCount ? '单' : '%'}
                                </div>
                            </div>
                        </React.Fragment>
                    )}
                    {/* 营收legend */}
                    {selectedChartType === enum_chart_type.revenue && (
                        <React.Fragment>
                            <div className={styles.revenueItem}>
                                <div className={styles.revenueTitle}>
                                    <div className={styles.legendIcon} style={{ background: '#FF6704' }} />
                                    营收
                                </div>
                                <div className={styles.revenueValue}>
                                    {(mainChartData.length > 0 &&
                                        mainChartData
                                            .reduce((preTotal, item) => preTotal + item.revenue || 0, 0)
                                            .toFixed(2)) ||
                                        0}
                                </div>
                            </div>
                            <div className={styles.revenueItem}>
                                <div className={styles.revenueTitle}>
                                    <div className={styles.legendIcon} style={{ background: '#999999' }} />
                                    成本
                                </div>
                                <div className={styles.revenueValue}>
                                    {(mainChartData.length > 0 &&
                                        mainChartData
                                            .reduce((preTotal, item) => preTotal + item.cost || 0, 0)
                                            .toFixed(2)) ||
                                        0}
                                </div>
                            </div>
                            <div className={styles.revenueItem}>
                                <div className={styles.revenueTitle}>
                                    <div className={styles.legendIcon} style={{ background: '#FDD903' }} />
                                    毛利
                                </div>
                                <div className={styles.revenueValue}>
                                    {(mainChartData.length > 0 &&
                                        mainChartData
                                            .reduce((preTotal, item) => preTotal + item.grossProfit || 0, 0)
                                            .toFixed(2)) ||
                                        0}
                                </div>
                            </div>
                        </React.Fragment>
                    )}
                    {/* 转介绍legend */}
                    {selectedChartType === enum_chart_type.positiveRate && (
                        <React.Fragment>
                            <div className={styles.positiveRateItem}>
                                <div className={styles.positiveRateTitle}>全部</div>
                                <div className={styles.positiveRateValue}>
                                    {getPositiveRateAve().all?.split('.')[0] || '0'}
                                    <span className={styles.positiveRateVal}>
                                        {`.${getPositiveRateAve().all?.split('.')[1] || '00%'}`}
                                    </span>
                                </div>
                            </div>
                            <div className={styles.positiveRateItem}>
                                <div className={styles.positiveRateTitle}>原价洗</div>
                                <div className={styles.positiveRateValue}>
                                    {(getPositiveRateAve().all &&
                                        getPositiveRateAve()[enum_order_discount_type.origin].split('.')[0]) ||
                                        '0'}
                                    <span className={styles.positiveRateVal}>
                                        {`.${(getPositiveRateAve().all &&
                                            getPositiveRateAve()[enum_order_discount_type.origin].split('.')[1]) ||
                                            '00%'}`}
                                    </span>
                                </div>
                            </div>
                            <div className={styles.positiveRateItem}>
                                <div className={styles.positiveRateTitle}>优惠洗</div>
                                <div className={styles.positiveRateValue}>
                                    {(getPositiveRateAve().all &&
                                        getPositiveRateAve()[enum_order_discount_type.discount].split('.')[0]) ||
                                        '0'}
                                    <span className={styles.positiveRateVal}>
                                        {`.${(getPositiveRateAve().all &&
                                            getPositiveRateAve()[enum_order_discount_type.discount].split('.')[1]) ||
                                            '00%'}`}
                                    </span>
                                </div>
                            </div>
                        </React.Fragment>
                    )}
                </div>
                <div className={styles.mainHeaderRight}>
                    <div onClick={_this.exportData} className={styles.exportBtn}>
                        导出
                    </div>
                    <div className="headerRightRadioGroup">
                        <Radio.Group value={selectedXAxisType} onChange={xAxisTypeChangeHandler}>
                            <Radio value={enum_xAxis_type.time}>时间</Radio>
                            <Radio value={enum_xAxis_type.area}>地区</Radio>
                        </Radio.Group>
                    </div>
                </div>
            </div>
        );
    }
}

export default ChartHeader;
