import React from 'react';
import { LeftOutlined } from '@ant-design/icons';
import { history } from 'umi';
import styles from './index.less';

interface IProps {
    className?: string; // 样式
}

const BackBtn = ({ className }: IProps): React.ReactElement => {
    const goToBack = () => {
        const { length, action } = history;
        if (length < 3 && action === 'POP') {
            // 如果已经没有更多历史记录，跳转到主页
            console.log('back to home');
            history.replace('/');
        } else {
            history.goBack();
        }
    };
    return (
        <div onClick={goToBack} className={`${styles.backBtn} ${className ? className : ''}`}>
            <LeftOutlined className={styles.backBtnIcon} />
        </div>
    );
};

export default BackBtn;
