import React from 'react';
import { findDOMNode } from 'react-dom';
import { inject, observer } from 'mobx-react';
import { UIStore } from '@/store/UI';
import { Chart, View, Geom, Axis, Legend, Tooltip } from 'bizcharts';
import styles from './index.less';

// 图表类型限定
export enum enum_geom_type {
    LINE = 'line', // 折线图
    LINE_STACK = 'lineStack', // 层叠折线图
    INTERVAL = 'interval', // 区间图
    INTERVAL_STACK = 'intervalStack', // 层叠区间图
    POINT = 'point', // 点图
    POINT_STACK = 'pointStack', // 层叠点图
    AREA = 'area', // 面积图
    AREA_STACK = 'areaStack' // 层叠面积图
}

export interface IAxisConfig {
    name: string; // 坐标轴字段
    visible?: boolean; // 坐标轴是否显示
}

// 图形配置项 例如多折线，则该对象为其中一条的配置，且至少需要一条折线的配置
export interface IConfigItem {
    typeKey: string | ((data) => string); // 字段名 找到 data[typeKey] 当作新的y轴值 如果是函数，则使用返回值作为y轴值
    typeName: string | ((data) => string); // 名称 如果是函数，则使用该函数的返回值作为分类内容
    newXValue?: (data: Record<string, any>) => string; // 重新计算x轴的值
    color: string | string[] | ((data) => string); // 颜色
}

// 图表对象
export interface IGeom {
    type: enum_geom_type; // 图表类型
    size?: string | number | [string, (d?: any) => number]; // 折线图 线宽，柱状图 柱宽
    adjust?: string; // 调整 例如使层叠分组散开
    configList: IConfigItem[]; // 配置列表
    otherOptions?: Record<string, any>; // 其他配置
}

// Index 和 CompoundChart 通用的属性
interface ICommonProps {
    data: Record<string, any>[];
    eventObj?: Record<string, any>; // 事件
    xConfig: IAxisConfig; // x轴配置 name 为横坐标字段
    yConfig: IAxisConfig; // y轴配置 name 为纵坐标字段
    geomList: IGeom[]; // geom列表
    padding?: number | string[] | 'auto'; // 边距
    scale?: Record<string, any>; // 配置数据比例尺 坐标轴配置
    className?: string; // 类名
    chartChildren?: React.ReactNode; // 自行增加Chart子节点 例如Axis Legend
    toolTipConfig?: Record<string, any>; // tooltip配置项
    geomChildren?: React.ReactNode;
    ifCanClick?: boolean; // 是否可点击，主要用来配置一些可点击的样式，例如鼠标hover
}

const REF_NAME = 'chartContainer'; // 通过该ref名称查找到图表的最外层 dom节点，从而获取高度

interface ICompoundChartProps extends ICommonProps {
    ifResize: boolean; // 必须传uiStore.ifResize 窗口变化的响应布局
    changeResize: Function; // 必须传uiStore.changeResize
}

interface ICompoundChartState {
    height: number; // chart高度
    geomData: any[]; // 整理后的data
}

class CompoundChart extends React.Component<ICompoundChartProps, ICompoundChartState> {
    private chartContainer: Element | Text | null = null; // 图表的最外层 dom节点

    constructor(props: ICompoundChartProps) {
        super(props);
        this.state = {
            height: 0,
            geomData: []
        };
    }

    componentDidMount() {
        const _this = this;
        _this.chartContainer = findDOMNode(_this.refs[REF_NAME]);
        _this.setChartHeight();
        window.onresize = () => {
            _this.props.changeResize();
        };
    }

    componentDidUpdate(preProps: ICompoundChartProps) {
        if (preProps.data !== this.props.data) {
            this.recombineData();
        }
        if (preProps.ifResize !== this.props.ifResize) {
            this.setChartHeight();
        }
    }

    setChartHeight = () => {
        const _this = this;
        _this.setState({
            height: _this.chartContainer?.clientHeight || 0
        });
    };

    // 整理数据，使其变成 [{ type: [以某个字段进行分类], [xKeyName]: [横坐标值], [yKeyName]: [纵坐标值] }] 的数据类型
    recombineData = () => {
        try {
            const newData: Record<string, any>[] = [];
            const { data, xConfig, yConfig, geomList } = this.props;
            data.forEach(dataItem =>
                // 遍历data进行数据重组
                geomList.forEach(typeItem =>
                    // 对每一种图表类型进行处理
                    typeItem.configList.forEach(configItem => {
                        // 对每一个图形进行处理
                        newData.push({
                            ...dataItem,
                            groupName:
                                configItem.typeName instanceof Function
                                    ? configItem.typeName(dataItem)
                                    : configItem.typeName,
                            [xConfig.name]:
                                configItem.typeName instanceof Function && configItem.newXValue
                                    ? configItem.newXValue(dataItem)
                                    : dataItem[xConfig.name],
                            [yConfig.name]:
                                configItem.typeKey instanceof Function
                                    ? configItem.typeKey(dataItem)
                                    : dataItem[configItem.typeKey]
                        });
                    })
                )
            );
            this.setState({ geomData: newData });
        } catch (e) {
            console.log(e);
        }
    };

    render() {
        const {
            scale,
            eventObj,
            xConfig,
            yConfig,
            geomList,
            padding,
            className,
            chartChildren,
            geomChildren,
            toolTipConfig,
            ifCanClick
        } = this.props;
        const { height, geomData } = this.state;
        const chartProps = {
            ...eventObj,
            height,
            forceFit: true,
            animate: false, // 关闭动画，由于较多高定制的图表，在数据变化时动画会频繁播放
            className: `${styles.chartContainer} ${className ? className : ''}`,
            placeholder: true, // 源码bug placeholder必须为true 才会显示默认的empty样式，且自定义jsx会报递归错误
            padding: padding || 'auto'
        };
        const viewProps = {
            animate: false, // 关闭动画，由于较多高定制的图表，在数据变化时动画会频繁播放
            data: geomData,
            scale: scale
        };
        return (
            <div ref={REF_NAME} className={`${styles.parentDom} ${ifCanClick ? styles.canClick : ''}`}>
                <Chart {...chartProps} {...viewProps}>
                    <Legend visible={false} />
                    <Tooltip {...toolTipConfig} />
                    <View {...viewProps}>
                        <Axis {...xConfig} />
                        <Axis {...yConfig} />
                        {geomList.map((geomItem, index) => {
                            const geomProps = {
                                animate: false,
                                type: geomItem.type,
                                size: geomItem.size,
                                adjust: geomItem.adjust,
                                position: `${xConfig.name}*${yConfig.name}`,
                                color: [
                                    'groupName',
                                    geomItem.configList.length === 1
                                        ? geomItem.configList[0].color
                                        : geomItem.configList.map(configItem => configItem.color)
                                ],
                                opacity: 1,
                                ...geomItem.otherOptions
                            };
                            return (
                                <Geom key={index} {...geomProps}>
                                    {geomChildren}
                                </Geom>
                            );
                        })}
                        {chartChildren}
                    </View>
                </Chart>
            </div>
        );
    }
}

interface IProps extends ICommonProps {
    uiStore?: UIStore; // 就是store.uiStore
}

const Index = inject('uiStore')(
    observer((props: IProps) => {
        const { uiStore } = props;
        return (
            <CompoundChart
                {...props}
                ifResize={uiStore?.ifResize || false}
                changeResize={uiStore?.changeResize || (() => {})}
            />
        );
    })
);

export default Index;
