import React from 'react';
import { Guide } from 'bizcharts';
import { errBoundary } from '@/components/ErrorBoundary';
import CompoundChart, { IGeom, enum_geom_type } from '@/components/CompoundChart';
import {
    enum_date_type,
    enum_xAxis_type,
    IRepurchaseRateDODItem,
    initRepurchaseRateDODItem
} from '@/store/Analysis/typings';
import { enum_area_type } from '../constant';
import { getWeekDayName, formatDate, debounce, getTicks } from '@/utils/method';
import styles from './RepurchaseRateChart.less';

interface IProps {
    dateType: enum_date_type; // 查询的日期类型
    xAxisType: enum_xAxis_type; // 查询的x轴类型
    data: Record<string, any>[]; // 图表数据
    areaType: enum_area_type; // 当前横坐标字段名
    clickHandler: Function; // 图形的点击事件
}

interface IState {
    activeData: Record<string, any>; // 当前选中的数据
    activeInterval: string; // 当前选中的柱状 横坐标字段内容
}

class RepurchaseRateChart extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            activeData: {},
            activeInterval: ''
        };
    }

    render() {
        const _this = this;
        const { activeData, activeInterval } = this.state;
        const { data, dateType, xAxisType, areaType, clickHandler } = this.props;
        let xKeyName = '';
        if (xAxisType === enum_xAxis_type.time) {
            switch (dateType) {
                case enum_date_type.day:
                    xKeyName = 'f_indate';
                    break;
                case enum_date_type.week:
                    xKeyName = 'week';
                    break;
                case enum_date_type.month:
                    xKeyName = 'month';
                    break;
            }
        } else {
            xKeyName = areaType;
        }
        // 计算辅助线文本的偏移量
        const getGuideOffset = length => {
            // 以20个tick需要便宜0.5个tick为基准，换算偏移量
            return length + (length / 20 - 1) * 0.5;
        };
        // 好评率geom
        const geomList: IGeom[] = [
            {
                type: enum_geom_type.LINE,
                configList: [
                    {
                        typeKey: 'repurchaseRate',
                        typeName: '复购率',
                        color: '#FDD903'
                    },
                    {
                        typeKey: 'turnoverRate',
                        typeName: '流失率',
                        color: '#999999'
                    }
                ]
            }
        ];

        // 坐标轴配置
        const xConfig = {
            name: xKeyName,
            line: {
                // x轴宽度 颜色
                lineWidth: 1,
                stroke: '#979797'
            },
            tickLine: null,
            label: {
                offset: 0, // 数值，设置坐标轴文本 label 距离坐标轴线的距离
                autoRotate: false, // 文本是否需要自动旋转，默认为 true
                htmlTemplate: (text, item, index) => {
                    const axisContent = {
                        line1: '',
                        line2: ''
                    };
                    if (xAxisType === enum_xAxis_type.time) {
                        switch (dateType) {
                            case enum_date_type.day:
                                axisContent.line1 =
                                    text === activeInterval ? formatDate(text, 'MM/DD') : getWeekDayName(text);
                                axisContent.line2 = '晴';
                                break;
                            case enum_date_type.week:
                                const weekArr = text.split('-');
                                axisContent.line1 = `${+weekArr[1]}周`;
                                axisContent.line2 = `${+weekArr[0]}`;
                                break;
                            case enum_date_type.month:
                                const monthArr = text.split('-');
                                axisContent.line1 = text === activeInterval ? `${+monthArr[1]}月` : monthArr[1];
                                axisContent.line2 = monthArr[0];
                                break;
                        }
                    } else {
                        axisContent.line1 = text;
                    }
                    return `<div class="${styles.dayAxis} ${text === activeInterval ? styles.activeDayAxis : ''}">
                        <div style="${axisContent.line1 === '一' && text !== activeInterval ? 'color: #FF6704' : ''}">
                            ${axisContent.line1}
                        </div>
                        <div>${axisContent.line2}</div>
                    </div>`;
                }
            }
        };
        const yConfig = {
            name: 'positiveRate',
            visible: false
        };

        const toolTipConfig = {
            shared: true,
            useHtml: true,
            showCrosshairs: true,
            crosshairs: {
                type: 'y',
                style: {
                    // 图形样式
                    stroke: '#4A4A4A' // 边框的颜色
                }
            },
            htmlContent: (title, items) => {
                const { _origin: data }: { _origin: IRepurchaseRateDODItem } = items[0].point;
                return `<div class=${styles.diyToolContainer}>
                    <div class=${styles.diyToolHeader}>
                        <div>复购率：</div>
                        <div class=${styles.orderValue}>${data.repurchaseRate}%</div>
                    </div>
                    <div class=${styles.diyToolLegend}>
                        <div class=${styles.diyToolLegendRow}>
                            <div class=${styles.icon} style="background: #FDD903"></div>
                            <div>流失率：${data.turnoverRate}</div>
                        </div>
                        <div class=${styles.diyToolLegendRow}>
                            <div class=${styles.icon} style="background: #FDD903"></div>
                            <div>洗车频次：${'--'}</div>
                        </div>
                    </div>
                </div>`;
            }
        };

        const chartChildren = () => {
            const targetRepurchaseRate = '45.00';
            return (
                <React.Fragment>
                    <Guide>
                        <Guide.Line
                            // top // {boolean} 指定 guide 是否绘制在 canvas 最上层，默认为 false, 即绘制在最下层
                            start={[0, targetRepurchaseRate]} // 0 代表ticks索引，必须scale的type为非线性
                            end={[getGuideOffset(data.length), targetRepurchaseRate]} // 同 start
                            lineStyle={{
                                stroke: '#615616', // 线的颜色
                                lineDash: [1, 0], // 虚线的设置，实线
                                opacity: 1,
                                lineWidth: 3 // 线的宽度
                            }} // {object} 图形样式配置 https://bizcharts.net/products/bizCharts/api/graphic#线条样式
                        />
                        <Guide.Html
                            position={[getGuideOffset(data.length), targetRepurchaseRate]} // html 的中心位置， 值为原始数据值，支持 callback
                            offsetX={0}
                            offsetY={0}
                            html={`<div class=${styles.guideContainer}>
                                <div class=${styles.guideTitle}>目标</div>
                                <div class=${styles.guideTag}>${targetRepurchaseRate}%</div>
                            </div>`}
                        />
                    </Guide>
                </React.Fragment>
            );
        };

        return (
            <div id="page-analysis-mainChart" className={styles.mainContainer}>
                <div className={styles.chartCard}>
                    <CompoundChart
                        data={data}
                        xConfig={xConfig}
                        yConfig={yConfig}
                        padding={['auto', '5%', 'auto', '2%']}
                        ifCanClick={xAxisType !== enum_xAxis_type.time && Boolean(activeInterval)}
                        scale={{
                            [xKeyName]: {
                                type: 'cat',
                                ticks: getTicks({
                                    length: data.length,
                                    activeTick: data.findIndex(item => item[xKeyName] === activeInterval)
                                })
                            },
                            [yConfig.name]: {
                                min: 0,
                                max: 100
                            }
                        }}
                        toolTipConfig={toolTipConfig}
                        geomList={geomList}
                        chartChildren={chartChildren()}
                        eventObj={{
                            onTooltipChange: debounce(event => {
                                const { _origin: data } = event.items[0].point;
                                _this.state.activeInterval !== data[xKeyName] &&
                                    _this.setState({
                                        activeData: data,
                                        activeInterval: data[xKeyName]
                                    });
                            }, 0),
                            onTooltipHide: debounce(event => {
                                activeInterval !== '' &&
                                    _this.setState({
                                        activeData: {},
                                        activeInterval: ''
                                    });
                            }, 0),
                            onPlotClick: debounce(event => {
                                if (activeInterval) {
                                    clickHandler(activeData);
                                }
                            }, 100)
                        }}
                    />
                </div>
            </div>
        );
    }
}

export default errBoundary(RepurchaseRateChart);
